import { renderHook } from "#test/browser"
import { useLocalStorage } from "./"

describe("useLocalStorage", () => {
  const key = "testKey"
  const initialValue = "initialValue"
  const problematicValue = {
    get error() {
      throw new Error("Error during serialization")
    },
  }
  const corruptedJSON = "{this-is-not:json}"

  beforeEach(() => {
    localStorage.clear()
  })

  test("returns the default value", async () => {
    const { result } = await renderHook(() => useLocalStorage({ key }))
    expect(result.current[0]).toBe("")
  })

  test("returns the default value in the initial state", async () => {
    const { result } = await renderHook(() =>
      useLocalStorage({ key, defaultValue: initialValue }),
    )
    expect(result.current[0]).toBe(initialValue)
  })

  test("sets a value and saves it to localStorage", async () => {
    const { act, result } = await renderHook(() =>
      useLocalStorage({ key, defaultValue: initialValue }),
    )

    await act(() => {
      result.current[1]("newValue")
    })

    expect(localStorage.getItem(key)).toBe(JSON.stringify("newValue"))
    expect(result.current[0]).toBe("newValue")
  })

  test("sets a value and callback function", async () => {
    const { act, result } = await renderHook(() =>
      useLocalStorage({ key, defaultValue: initialValue }),
    )

    await act(() => {
      result.current[1]((prev) => `prev-${prev}`)
    })

    expect(localStorage.getItem(key)).toBe(JSON.stringify("prev-initialValue"))
    expect(result.current[0]).toBe("prev-initialValue")
  })

  test("removes a value from localStorage", async () => {
    const { act, result } = await renderHook(() =>
      useLocalStorage({ key, defaultValue: initialValue }),
    )

    await act(() => {
      result.current[2]()
    })

    expect(localStorage.getItem(key)).toBeNull()
    expect(result.current[0]).toBe(initialValue)
  })

  test("updates the value when a storage event occurs", async () => {
    const { act, result } = await renderHook(() =>
      useLocalStorage({ key, defaultValue: initialValue }),
    )

    await act(() => {
      window.dispatchEvent(
        new StorageEvent("storage", {
          key,
          newValue: JSON.stringify("updatedValue"),
          storageArea: window.localStorage,
        }),
      )
    })

    expect(result.current[0]).toBe("updatedValue")
  })

  test("uses a custom serialize function", async () => {
    const serialize = (value: unknown) => `serialized-${String(value)}`

    const { act, result } = await renderHook(() =>
      useLocalStorage({
        key,
        defaultValue: initialValue,
        serialize,
      }),
    )

    await act(() => {
      result.current[1]("testValue")
    })

    expect(localStorage.getItem(key)).toBe("serialized-testValue")
  })

  test("uses a custom deserialize function", async () => {
    const deserialize = (value: string | undefined) => `deserialized-${value}`

    localStorage.setItem(key, initialValue)

    const { result } = await renderHook(() =>
      useLocalStorage({
        key,
        deserialize,
      }),
    )

    expect(result.current[0]).toBe("deserialized-initialValue")
  })

  test("serializeJSON throws an error when serialization fails", async () => {
    const { act, result } = await renderHook(() =>
      useLocalStorage({
        key,
        defaultValue: problematicValue,
      }),
    )

    await expect(async () => {
      await act(() => {
        result.current[1](problematicValue)
      })
    }).rejects.toThrow(
      "useLocalStorage use-local-storage: Failed to serialize the value",
    )
  })

  test("deserializeJSON returns input if JSON parsing fails", async () => {
    localStorage.setItem(key, corruptedJSON)

    const { result } = await renderHook(() => useLocalStorage({ key }))

    expect(result.current[0]).toBe(corruptedJSON)
  })

  test("deserializeJSON returns input if empty", async () => {
    localStorage.setItem(key, "")

    const { result } = await renderHook(() => useLocalStorage({ key }))

    expect(result.current[0]).toBe("")
  })
})

"use client"

import { useCallback, useEffect, useState } from "react"
import { isFunction } from "@yamada-ui/react"
import { useWindowEvent } from "../use-window-event"

export type StorageType = "localStorage" | "sessionStorage"

export interface StorageProps<Y> {
  key: string
  defaultValue?: Y
  getInitialValueInEffect?: boolean
  deserialize?: (value: string | undefined) => Y
  serialize?: (value: Y) => string
}

const serializeJSON = <Y>(value: Y, name: string) => {
  try {
    return JSON.stringify(value)
  } catch {
    throw new Error(`useLocalStorage ${name}: Failed to serialize the value`)
  }
}

const deserializeJSON = (value: string | undefined) => {
  if (!value) return value

  try {
    return JSON.parse(value)
  } catch {
    return value
  }
}

export const createStorage = <Y>(type: StorageType, name: string) => {
  const eventName =
    type === "localStorage" ? "local-storage" : "session-storage"

  return ({
    key,
    defaultValue,
    deserialize = deserializeJSON,
    getInitialValueInEffect = true,
    serialize = (value: Y) => serializeJSON(value, name),
  }: StorageProps<Y>) => {
    const readStorageValue = useCallback(
      (skipStorage?: boolean): Y => {
        if (
          typeof window === "undefined" ||
          !(type in window) ||
          (window[type] as null | Storage | undefined) == null ||
          skipStorage
        ) {
          return (defaultValue ?? "") as Y
        }

        const storageValue = window[type].getItem(key)

        return storageValue !== null
          ? deserialize(storageValue)
          : ((defaultValue ?? "") as Y)
      },
      [key, deserialize, defaultValue],
    )

    const [value, setValue] = useState<Y>(
      readStorageValue(getInitialValueInEffect),
    )

    const setStorageValue = useCallback(
      (valOrFn: ((prevState: Y) => Y) | Y) => {
        if (isFunction(valOrFn)) {
          setValue((current) => {
            const result = valOrFn(current)

            window[type].setItem(key, serialize(result))
            window.dispatchEvent(
              new CustomEvent(eventName, {
                detail: { key, value: valOrFn(current) },
              }),
            )

            return result
          })
        } else {
          window[type].setItem(key, serialize(valOrFn))
          window.dispatchEvent(
            new CustomEvent(eventName, { detail: { key, value: valOrFn } }),
          )

          setValue(valOrFn)
        }
      },
      [key, serialize],
    )

    const removeStorageValue = useCallback(() => {
      window[type].removeItem(key)
      setValue(defaultValue as Y)
    }, [defaultValue, key])

    useWindowEvent("storage", (ev) => {
      if (ev.storageArea === window[type] && ev.key === key)
        setValue(deserialize(ev.newValue ?? undefined))
    })

    useWindowEvent(eventName, (ev) => {
      if (ev.detail.key === key) setValue(ev.detail.value)
    })

    useEffect(() => {
      if (defaultValue !== undefined && value === undefined)
        setStorageValue(defaultValue)
    }, [defaultValue, value, setStorageValue])

    useEffect(() => {
      if (getInitialValueInEffect) setValue(readStorageValue())
    }, [getInitialValueInEffect, readStorageValue])

    return [
      value === undefined ? defaultValue : value,
      setStorageValue,
      removeStorageValue,
    ] as const
  }
}

/**
 * `useLocalStorage` is a custom hook for storing, updating, and retrieving values in local storage.
 *
 * @see https://yamada-ui.com/docs/hooks/use-local-storage
 */
export const useLocalStorage = <Y = string>(props: StorageProps<Y>) =>
  createStorage<Y>("localStorage", "use-local-storage")(props)
